mapper.select:
SELECT query_text, COUNT(*) as count FROM steering_query_log
WHERE created_at >= NOW() - (#{days} || ' days')::INTERVAL
GROUP BY query_text ORDER BY count DESC LIMIT #{limit}

SELECT agent_name as agent_id, COUNT(*) as count FROM steering_query_log
WHERE agent_name IS NOT NULL AND created_at >= NOW() - (#{days} || ' days')::INTERVAL
GROUP BY agent_name ORDER BY count DESC LIMIT #{limit}
